def _stripped_optional_str(val: str | None) -> str | None:
    if val is None:
        return None
    t = val.strip()
    return t or None


def _materialize_stair_runs_and_landings(
    cmd: CreateStairCmd,
) -> tuple[list[StairRun], list[StairLanding]]:
    """KRN-07: derive runs/landings from a CreateStairCmd.

    - Explicit runs[] passed by the caller win.
    - For shape='straight' with no runs, derive a single run from runStartMm/runEndMm.
    - For shape='l_shape'/'u_shape' with caller-supplied runs but no landings,
      auto-derive a rectangular landing per gap from adjacent run endpoints + width.
    """

    runs = list(cmd.runs)
    landings = list(cmd.landings)

    if not runs and cmd.shape == "straight":
        runs = [
            StairRun(
                id=f"{cmd.id or 'stair'}-run-1",
                start_mm=cmd.run_start_mm,
                end_mm=cmd.run_end_mm,
                width_mm=cmd.width_mm,
                riser_count=8,
            )
        ]

    if cmd.shape in ("l_shape", "u_shape") and runs and not landings:
        for i in range(len(runs) - 1):
            a = runs[i]
            b = runs[i + 1]
            landings.append(_auto_landing_for_gap(f"{cmd.id or 'stair'}-landing-{i + 1}", a, b))

    return runs, landings


def _auto_landing_for_gap(landing_id: str, a: StairRun, b: StairRun) -> StairLanding:
    """KRN-07: square landing centered on the join between runs `a` and `b`.

    Uses the larger of the two run widths so the landing always covers both treads.
    """

    cx = (a.end_mm.x_mm + b.start_mm.x_mm) * 0.5
    cy = (a.end_mm.y_mm + b.start_mm.y_mm) * 0.5
    half = max(a.width_mm, b.width_mm) * 0.5
    return StairLanding(
        id=landing_id,
        boundary_mm=[
            Vec2Mm(xMm=cx - half, yMm=cy - half),
            Vec2Mm(xMm=cx + half, yMm=cy - half),
            Vec2Mm(xMm=cx + half, yMm=cy + half),
            Vec2Mm(xMm=cx - half, yMm=cy + half),
        ],
    )


def _room_programme_field_updates(
    programme_code: str | None,
    department: str | None,
    function_label: str | None,
    finish_set: str | None,
    target_area_m2: float | None = None,
) -> dict[str, Any]:
    out: dict[str, Any] = {
        "programme_code": _stripped_optional_str(programme_code),
        "department": _stripped_optional_str(department),
        "function_label": _stripped_optional_str(function_label),
        "finish_set": _stripped_optional_str(finish_set),
    }
    if target_area_m2 is not None:
        if target_area_m2 <= 0:
            raise ValueError("targetAreaM2 must be positive when set")
        out["target_area_m2"] = float(target_area_m2)
    return out


def coerce_command(data: dict[str, Any]) -> Command:
    return command_adapter.validate_python(data)


def _dump_elements(elements: dict[str, Element]) -> dict[str, Any]:
    return {k: v.model_dump(by_alias=True) for k, v in elements.items()}


def clone_document(doc: Document) -> Document:
    payload = {"revision": doc.revision, "elements": _dump_elements(doc.elements)}
    return Document.model_validate(payload)


def ensure_internal_origin(doc: Document) -> Document:
    """KRN-06: ensure the singleton `internal_origin` element exists.

    Mutates `doc.elements` in place when missing and returns the same Document.
    Idempotent. Called on model creation and on first snapshot read so legacy
    models acquire one without requiring a migration.
    """
    if any(isinstance(e, InternalOriginElem) for e in doc.elements.values()):
        return doc
    doc.elements[INTERNAL_ORIGIN_ID] = InternalOriginElem(
        kind="internal_origin", id=INTERNAL_ORIGIN_ID
    )
    return doc

